// ── HTTP Error Messages (Chinese) ────────────────────────────────────────────

const STATUS_MESSAGES: Record<number, string> = {
  400: '请求格式错误，请检查请求参数',
  401: 'API 密钥无效或已过期，请检查 MT_API_KEY 或 .mt-env 配置',
  403: '无权限执行此操作',
  404: '请求的资源不存在，请检查 URL 和 ID',
  409: '操作冲突，资源状态已变更，请刷新后重试',
  422: '请求数据验证失败，请检查字段格式',
  429: '请求过于频繁，请稍后重试',
  500: '服务器内部错误，请联系管理员',
  502: '网关错误，服务器暂时不可用',
  503: '服务暂时不可用，请稍后重试',
};

function getStatusMessage(status: number): string {
  return STATUS_MESSAGES[status] || `未知错误 (HTTP ${status})`;
}

function getSuggestion(status: number): string {
  switch (status) {
    case 400:
    case 422:
      return '[建议] 检查请求参数是否符合 API 规范';
    case 401:
      return '[建议] 重新获取 API 密钥或检查 .mt-cli.json 中的 key 配置';
    case 404:
      return '[建议] 使用 mt-cli status 确认服务器地址和里程碑 ID';
    case 409:
      return '[建议] 先查询最新状态 (mt-cli list)，再尝试操作';
    default:
      return '[建议] 稍后重试，或使用 mt-cli status 检查服务器连通性';
  }
}

// ── Error Class ─────────────────────────────────────────────────────────────

export class MtCliError extends Error {
  constructor(
    public readonly status: number,
    public readonly message: string,
    public readonly suggestion: string,
    public readonly url: string,
  ) {
    super(`[错误] HTTP ${status}: ${message}\n${suggestion}`);
    this.name = 'MtCliError';
  }
}

// ── HTTP Client ─────────────────────────────────────────────────────────────

export interface MtClientOptions {
  baseUrl: string;
  apiKey: string;
  timeoutMs?: number;
}

export class MtClient {
  private baseUrl: string;
  private apiKey: string;
  private timeoutMs: number;

  constructor(opts: MtClientOptions) {
    this.baseUrl = opts.baseUrl.replace(/\/+$/, '');
    this.apiKey = opts.apiKey;
    this.timeoutMs = opts.timeoutMs ?? 10_000;
  }

  private headers(): Record<string, string> {
    return {
      'Authorization': `Bearer ${this.apiKey}`,
      'Content-Type': 'application/json',
      'Accept': 'application/json',
    };
  }

  async get<T>(path: string): Promise<T> {
    return this.request<T>('GET', path);
  }

  async post<T>(path: string, body?: unknown): Promise<T> {
    return this.request<T>('POST', path, body);
  }

  async patch<T>(path: string, body?: unknown): Promise<T> {
    return this.request<T>('PATCH', path, body);
  }

  private async request<T>(method: string, path: string, body?: unknown): Promise<T> {
    const url = `${this.baseUrl}${path}`;
    const controller = new AbortController();
    const timer = setTimeout(() => controller.abort(), this.timeoutMs);

    try {
      const response = await fetch(url, {
        method,
        headers: this.headers(),
        body: body !== undefined ? JSON.stringify(body) : undefined,
        signal: controller.signal,
      });

      clearTimeout(timer);

      // Log request on failure
      if (!response.ok) {
        console.error(`[HTTP] ${method} ${url} → ${response.status}`);
      }

      let data: unknown;
      const text = await response.text();
      try {
        data = JSON.parse(text);
      } catch {
        // Non-JSON response
        if (!response.ok) {
          throw new MtCliError(
            response.status,
            `服务器返回非 JSON 响应: ${text.slice(0, 200)}`,
            getSuggestion(response.status),
            url,
          );
        }
        throw new Error(`[错误] 无法解析服务器响应为 JSON`);
      }

      if (!response.ok) {
        const errData = data as Record<string, unknown>;
        const message =
          (errData['message'] as string) ||
          (errData['error'] as string) ||
          getStatusMessage(response.status);
        throw new MtCliError(response.status, message, getSuggestion(response.status), url);
      }

      return data as T;
    } catch (err) {
      clearTimeout(timer);
      if (err instanceof MtCliError) throw err;
      if (err instanceof DOMException && err.name === 'AbortError') {
        throw new MtCliError(
          0,
          `请求超时 (${this.timeoutMs}ms)，服务器未响应`,
          '[建议] 检查服务器是否运行，或使用 mt-cli status 测试连通性',
          url,
        );
      }
      if (err instanceof TypeError && (err as Error).message.includes('fetch')) {
        throw new MtCliError(
          0,
          `无法连接到服务器: ${(err as Error).message}`,
          '[建议] 检查 serverUrl 配置和服务器运行状态',
          url,
        );
      }
      throw err;
    }
  }
}

import type { Command } from 'commander';
import type { ResolvedConfig } from '../config.js';
import { MtClient } from '../client.js';
import type { TaskResponse } from '../types.js';
import { parseTaskId, resolveTaskId } from '../utils/id.js';

export function registerClaimCommand(
  tasksGroup: Command,
  getConfig: () => ResolvedConfig,
): void {
  tasksGroup
    .command('claim <taskId>')
    .description('领取一个任务')
    .option('--agent <name>', 'Agent 名称（默认使用配置中的 agentName）')
    .action(async (taskId: string, opts: { agent?: string }) => {
      const config = getConfig();
      const client = new MtClient({ baseUrl: config.serverUrl, apiKey: config.apiKey });

      const agentName = opts.agent || config.agentName;
      if (!agentName) {
        console.error('[错误] 未指定 Agent 名称。请使用 --agent <name> 或在配置文件中设置 agentName。');
        process.exit(1);
      }

      try {
        const parsed = parseTaskId(taskId);
        const fullId = await resolveTaskId(parsed, () =>
          client.get<TaskResponse[]>(`/api/tasks?milestoneId=${encodeURIComponent(config.milestoneId)}`),
        );

        const result = await client.post<TaskResponse>(`/api/tasks/${encodeURIComponent(fullId)}/claim`, {
          assignee: agentName,
        });

        console.log(`✓ 已领取 #${result.shortId}「${result.title}」`);
        console.log(`  负责人: ${result.assignee}`);
      } catch (err) {
        if (err instanceof Error) {
          const msg = err.message;
          // Check for 409 conflict
          if (msg.includes('409')) {
            console.error(`✗ 领取失败。任务 ${taskId} 已被其他 Agent 领取。`);
            console.error(`  请执行 'mt-cli tasks list --status todo' 查看可用任务。`);
          } else {
            console.error(msg);
          }
        }
        process.exit(1);
      }
    });
}

// ── Chinese Formatting Helpers ──────────────────────────────────────────────

import type { TaskStatus } from '../types.js';

// ── Status Labels ───────────────────────────────────────────────────────────

const STATUS_LABELS: Record<TaskStatus, string> = {
  todo: '待领取',
  'in-progress': '进行中',
  blocked: '阻塞',
  review: '审核中',
  done: '已完成',
  skipped: '已跳过',
};

export function statusLabel(status: string): string {
  return (STATUS_LABELS as Record<string, string>)[status] || status;
}

// ── Progress Bar ────────────────────────────────────────────────────────────

export function progressBar(subDone: number, subTotal: number, width = 20): string {
  if (subTotal <= 0) return '—';
  const pct = Math.round((subDone / subTotal) * 100);
  const filled = Math.round((subDone / subTotal) * width);
  const empty = width - filled;
  return `[${'█'.repeat(filled)}${'░'.repeat(empty)}] ${pct}%`;
}

// ── Divider ─────────────────────────────────────────────────────────────────

export function divider(char = '─', width = 40): string {
  return char.repeat(width);
}

export function sectionHeader(title: string): string {
  return `\n${divider('═', 40)}\n  ${title}\n${divider('═', 40)}`;
}

// ── Date Formatting ─────────────────────────────────────────────────────────

export function formatDate(isoStr: string | null | undefined): string {
  if (!isoStr) return '—';
  try {
    const d = new Date(isoStr);
    const pad = (n: number) => String(n).padStart(2, '0');
    return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())} ${pad(d.getHours())}:${pad(d.getMinutes())}`;
  } catch {
    return '—';
  }
}

// ── Task Row Formatting ─────────────────────────────────────────────────────

export function taskRow(task: {
  shortId: number;
  title: string;
  moduleId: string;
  status: string;
  assignee: string | null;
  subTotal: number;
  subDone: number;
}): string {
  const id = `#${task.shortId}`.padEnd(6);
  const status = statusLabel(task.status).padEnd(8);
  const module = task.moduleId.padEnd(16);
  const assignee = (task.assignee || '—').padEnd(12);
  const progress = task.subTotal > 0
    ? progressBar(task.subDone, task.subTotal)
    : '';
  return `${id} ${task.title}\n      状态: ${status}  模块: ${module}  负责人: ${assignee}${progress ? '  ' + progress : ''}`;
}

// ── Task ID Parsing and Resolution ──────────────────────────────────────────

import type { TaskResponse } from '../types.js';

export interface ParsedTaskId {
  type: 'full' | 'short';
  fullId?: string;      // TASK-{seq}
  shortId?: number;     // N (from #N)
}

/**
 * Parse task ID input.
 * - `#N` → short ID reference
 * - `TASK-{seq}` → full ID
 * - Bare number → treated as short ID
 */
export function parseTaskId(input: string): ParsedTaskId {
  const trimmed = input.trim();

  // #N format
  const shortMatch = trimmed.match(/^#(\d+)$/);
  if (shortMatch) {
    return { type: 'short', shortId: parseInt(shortMatch[1], 10) };
  }

  // TASK-{seq} format
  const fullMatch = trimmed.match(/^TASK-(\d+)$/i);
  if (fullMatch) {
    return { type: 'full', fullId: `TASK-${fullMatch[1]}` };
  }

  // Bare number → treat as short ID
  const bareNum = trimmed.match(/^(\d+)$/);
  if (bareNum) {
    return { type: 'short', shortId: parseInt(bareNum[1], 10) };
  }

  // Unknown format — pass through as full ID
  return { type: 'full', fullId: trimmed };
}

/**
 * Resolve a parsed task ID to a full task ID.
 * If it's a short ID, look up the full ID from the task list.
 */
export async function resolveTaskId(
  parsed: ParsedTaskId,
  listTasks: () => Promise<TaskResponse[]>,
): Promise<string> {
  if (parsed.type === 'full' && parsed.fullId) {
    return parsed.fullId;
  }

  if (parsed.type === 'short' && parsed.shortId !== undefined) {
    const tasks = await listTasks();
    const match = tasks.find((t) => t.shortId === parsed.shortId);
    if (!match) {
      throw new Error(
        `[错误] 未找到编号 #${parsed.shortId} 的任务。请使用 'mt-cli tasks list' 查看所有任务。`
      );
    }
    return match.id;
  }

  throw new Error(`[错误] 无法解析任务 ID: ${JSON.stringify(parsed)}`);
}

/**
 * Find a task by short ID from a list.
 */
export function findByShortId(tasks: TaskResponse[], shortId: number): TaskResponse | undefined {
  return tasks.find((t) => t.shortId === shortId);
}

import { json } from '@sveltejs/kit';
import type { RequestHandler } from './$types.js';
import { db } from '$lib/db/index.js';
import { claimTask } from '$lib/server/task-service.js';
import { claimTaskSchema } from '$lib/schemas/index.js';

export const POST: RequestHandler = async ({ params, request }) => {
	let body: unknown;
	try {
		body = await request.json();
	} catch {
		return json({ error: 'invalid_json', message: 'Request body must be valid JSON' }, { status: 400 });
	}

	const parsed = claimTaskSchema.safeParse(body);
	if (!parsed.success) {
		return json(
			{
				error: 'validation_error',
				message: 'Validation failed',
				details: parsed.error.issues.map((i) => ({
					field: i.path.join('.'),
					message: i.message
				}))
			},
			{ status: 400 }
		);
	}

	const result = await claimTask(db, params.id, parsed.data);

	if (result.error === 'not_found') {
		return json({ error: 'not_found', message: `Task ${params.id} not found` }, { status: 404 });
	}
	if (result.error === 'invalid_status') {
		return json(
			{
				error: 'invalid_status',
				message: `Cannot claim task in status: ${result.currentStatus}`,
				currentStatus: result.currentStatus
			},
			{ status: 400 }
		);
	}
	if (result.error === 'conflict') {
		return json(
			{
				error: 'conflict',
				message: `Task already claimed by ${result.currentAssignee}`,
				currentAssignee: result.currentAssignee
			},
			{ status: 409 }
		);
	}

	return json(result.task);
};

import { eq, asc, sql, and, inArray } from 'drizzle-orm';
import type { BetterSQLite3Database } from 'drizzle-orm/better-sqlite3';
import { tasks, modules, milestones } from '$lib/db/schema.js';
import type { TaskStatus } from '$lib/db/schema.js';
import type {
	ClaimTaskInput,
	ProgressTaskInput,
	CompleteTaskInput,
	AdminTaskActionInput,
	UpdateTaskInput
} from '$lib/schemas/index.js';
import { isValidTransition } from '$lib/schemas/index.js';

// ── ID Generation ────────────────────────────────────────────────────────────

/** Get next TASK-{global_seq} ID and short_id. */
export async function nextTaskId(db: BetterSQLite3Database<any>): Promise<{ id: string; shortId: number }> {
	const rows = await db.select({ id: tasks.id, shortId: tasks.shortId }).from(tasks).all();
	let maxSeq = 0;
	let maxShort = 0;
	for (const row of rows) {
		const seq = parseInt(row.id.replace('TASK-', ''), 10);
		if (seq > maxSeq) maxSeq = seq;
		if (row.shortId > maxShort) maxShort = row.shortId;
	}
	return { id: `TASK-${maxSeq + 1}`, shortId: maxShort + 1 };
}

// ── List (with filters) ─────────────────────────────────────────────────────

export interface TaskFilters {
	status?: string;
	milestoneId?: string;
	moduleId?: string;
}

export async function listTasks(
	db: BetterSQLite3Database<any>,
	filters: TaskFilters = {}
) {
	const conditions = [];
	if (filters.status) conditions.push(eq(tasks.status, filters.status as TaskStatus));
	if (filters.moduleId) conditions.push(eq(tasks.moduleId, filters.moduleId));

	// If milestoneId, join through modules
	if (filters.milestoneId) {
		const modRows = await db
			.select({ id: modules.id })
			.from(modules)
			.where(eq(modules.milestoneId, filters.milestoneId))
			.all();
		const modIds = modRows.map((m) => m.id);
		if (modIds.length === 0) return [];
		conditions.push(inArray(tasks.moduleId, modIds));
	}

	const whereClause = conditions.length > 0 ? and(...conditions) : undefined;
	const rows = await db
		.select()
		.from(tasks)
		.where(whereClause)
		.orderBy(asc(tasks.shortId))
		.all();
	return rows.map(formatTaskResponse);
}

// ── Get Detail ───────────────────────────────────────────────────────────────

export async function getTask(
	db: BetterSQLite3Database<any>,
	id: string
) {
	const row = await db.select().from(tasks).where(eq(tasks.id, id)).get();
	if (!row) return null;

	// Resolve module and milestone info
	const mod = await db.select().from(modules).where(eq(modules.id, row.moduleId)).get();
	const milestone = mod
		? await db.select().from(milestones).where(eq(milestones.id, mod.milestoneId)).get()
		: null;

	return {
		...formatTaskResponse(row),
		module: mod
			? {
					id: mod.id,
					milestoneId: mod.milestoneId,
					name: mod.name,
					status: mod.status
				}
			: null,
		milestone: milestone
			? {
					id: milestone.id,
					title: milestone.title,
					status: milestone.status
				}
			: null
	};
}

// ── Claim (optimistic lock) ──────────────────────────────────────────────────

export async function claimTask(
	db: BetterSQLite3Database<any>,
	id: string,
	data: ClaimTaskInput
) {
	const existing = await db.select().from(tasks).where(eq(tasks.id, id)).get();
	if (!existing) return { error: 'not_found' as const };

	// Only allow claiming if task is todo or in-progress
	if (existing.status !== 'todo' && existing.status !== 'in-progress') {
		return { error: 'invalid_status' as const, currentStatus: existing.status };
	}

	// Optimistic lock: if already assigned to someone else, reject
	if (existing.assignee && existing.assignee !== data.assignee) {
		return {
			error: 'conflict' as const,
			currentAssignee: existing.assignee,
			task: formatTaskResponse(existing)
		};
	}

	// Transition status if needed
	const statusUpdate =
		existing.status === 'todo' ? 'in-progress' : undefined;

	const updates: Record<string, any> = { assignee: data.assignee };
	if (statusUpdate) updates.status = statusUpdate;
	updates.updatedAt = sql`(unixepoch())`;

	const result = await db
		.update(tasks)
		.set(updates)
		.where(eq(tasks.id, id))
		.returning()
		.get();

	return { task: formatTaskResponse(result) };
}

// ── Progress ─────────────────────────────────────────────────────────────────

export async function progressTask(
	db: BetterSQLite3Database<any>,
	id: string,
	data: ProgressTaskInput
) {
	const existing = await db.select().from(tasks).where(eq(tasks.id, id)).get();
	if (!existing) return { error: 'not_found' as const };

	if (existing.status !== 'in-progress' && existing.status !== 'todo' && existing.status !== 'blocked') {
		return { error: 'invalid_status' as const, currentStatus: existing.status };
	}

	const updates: Record<string, any> = { updatedAt: sql`(unixepoch())` };
	if (data.progressMessage !== undefined) updates.progressMessage = data.progressMessage ?? null;
	if (data.subTotal !== undefined) updates.subTotal = data.subTotal;
	if (data.subDone !== undefined) updates.subDone = data.subDone;

	const result = await db
		.update(tasks)
		.set(updates)
		.where(eq(tasks.id, id))
		.returning()
		.get();

	return { task: formatTaskResponse(result) };
}

// ── Complete ─────────────────────────────────────────────────────────────────

export async function completeTask(
	db: BetterSQLite3Database<any>,
	id: string,
	data: CompleteTaskInput
) {
	const existing = await db.select().from(tasks).where(eq(tasks.id, id)).get();
	if (!existing) return { error: 'not_found' as const };

	// Must be in review or in-progress to complete
	if (existing.status !== 'review' && existing.status !== 'in-progress') {
		return { error: 'invalid_status' as const, currentStatus: existing.status };
	}

	const updates: Record<string, any> = {
		status: 'done',
		updatedAt: sql`(unixepoch())`,
		reportedAt: sql`(unixepoch())`
	};
	if (data.commitHash !== undefined) updates.commitHash = data.commitHash ?? null;
	if (data.progressMessage !== undefined) updates.progressMessage = data.progressMessage ?? null;

	const result = await db
		.update(tasks)
		.set(updates)
		.where(eq(tasks.id, id))
		.returning()
		.get();

	return { task: formatTaskResponse(result) };
}

// ── Admin Action ─────────────────────────────────────────────────────────────

export type AdminActionError = {
	error: 'not_found' | 'invalid_transition' | 'invalid_status';
	detail?: string;
};

export async function adminTaskAction(
	db: BetterSQLite3Database<any>,
	id: string,
	data: AdminTaskActionInput
) {
	const existing = await db.select().from(tasks).where(eq(tasks.id, id)).get();
	if (!existing) return { error: 'not_found' as const };

	// Admin can force any status, but validate transition for non-force actions
	// For admin actions, we allow any status change (admin override)
	const updates: Record<string, any> = {
		status: data.status,
		updatedAt: sql`(unixepoch())`
	};

	// If setting to done, also set reportedAt
	if (data.status === 'done' && !existing.reportedAt) {
		updates.reportedAt = sql`(unixepoch())`;
	}
	// If reopening from done, clear reportedAt
	if (data.status !== 'done' && existing.reportedAt) {
		updates.reportedAt = null;
	}

	if (data.progressMessage !== undefined) {
		updates.progressMessage = data.progressMessage ?? null;
	}

	// Handle assignee clearing (force release) or assignment
	if (data.assignee !== undefined) {
		updates.assignee = data.assignee ?? null;
	}

	const result = await db
		.update(tasks)
		.set(updates)
		.where(eq(tasks.id, id))
		.returning()
		.get();

	return { task: formatTaskResponse(result) };
}

// ── Update task (edit properties) ───────────────────────────────────────────

export async function updateTask(
	db: BetterSQLite3Database<any>,
	id: string,
	data: UpdateTaskInput
) {
	const existing = await db.select().from(tasks).where(eq(tasks.id, id)).get();
	if (!existing) return { error: 'not_found' as const };

	const updates: Record<string, any> = { updatedAt: sql`(unixepoch())` };
	if (data.title !== undefined) updates.title = data.title;
	if (data.description !== undefined) updates.description = data.description ?? null;
	if (data.assignee !== undefined) updates.assignee = data.assignee ?? null;

	const result = await db
		.update(tasks)
		.set(updates)
		.where(eq(tasks.id, id))
		.returning()
		.get();

	return { task: formatTaskResponse(result) };
}

// ── Kanban Data (with zombie detection) ─────────────────────────────────────

const ZOMBIE_THRESHOLD_MS = 24 * 60 * 60 * 1000; // 24 hours

export async function listKanbanData(db: BetterSQLite3Database<any>, milestoneId: string) {
	// Fetch milestone
	const milestone = await db.select().from(milestones).where(eq(milestones.id, milestoneId)).get();
	if (!milestone) return null;

	// Fetch modules
	const modRows = await db
		.select()
		.from(modules)
		.where(eq(modules.milestoneId, milestoneId))
		.orderBy(asc(modules.sortOrder))
		.all();

	const now = Date.now();

	// Fetch tasks per module with zombie flag
	const modulesWithTasks = await Promise.all(
		modRows.map(async (mod) => {
			const taskRows = await db
				.select()
				.from(tasks)
				.where(eq(tasks.moduleId, mod.id))
				.all();

			const tasksWithZombie = taskRows.map((row) => {
				const formatted = formatTaskResponse(row);
				const isZombie =
					row.status === 'in-progress' &&
					(now - new Date(row.updatedAt).getTime()) > ZOMBIE_THRESHOLD_MS;
				return { ...formatted, isZombie };
			});

			const totalTasks = tasksWithZombie.length;
			const doneTasks = tasksWithZombie.filter((t) => t.status === 'done').length;
			const progressPercent = totalTasks > 0 ? Math.round((doneTasks / totalTasks) * 100) : 0;

			// Collect unique assignees
			const assignees = [...new Set(tasksWithZombie.map((t) => t.assignee).filter(Boolean))];

			return {
				...formatModuleResponse(mod),
				tasks: tasksWithZombie,
				totalTasks,
				doneTasks,
				progressPercent,
				assignees
			};
		})
	);

	return {
		...formatMilestoneResponse(milestone),
		modules: modulesWithTasks
	};
}

// ── Formatters ───────────────────────────────────────────────────────────────

function formatMilestoneResponse(row: any) {
	return {
		id: row.id,
		title: row.title,
		sourceMd: row.sourceMd,
		gitUrl: row.gitUrl,
		status: row.status,
		createdAt: new Date(row.createdAt).toISOString()
	};
}

function formatModuleResponse(row: any) {
	return {
		id: row.id,
		milestoneId: row.milestoneId,
		name: row.name,
		description: row.description,
		status: row.status,
		sortOrder: row.sortOrder
	};
}

// ── Formatter ────────────────────────────────────────────────────────────────

function formatTaskResponse(row: any) {
	return {
		id: row.id,
		shortId: row.shortId,
		moduleId: row.moduleId,
		title: row.title,
		description: row.description,
		references: row.references,
		status: row.status,
		assignee: row.assignee,
		subTotal: row.subTotal,
		subDone: row.subDone,
		progressMessage: row.progressMessage,
		commitHash: row.commitHash,
		createdAt: new Date(row.createdAt).toISOString(),
		updatedAt: new Date(row.updatedAt).toISOString(),
		reportedAt: row.reportedAt ? new Date(row.reportedAt).toISOString() : null
	};
}

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { MtClient, MtCliError } from '../client.js';

// Mock global fetch
const mockFetch = vi.fn();
vi.stubGlobal('fetch', mockFetch);

describe('MtClient', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  afterEach(() => {
    vi.restoreAllMocks();
  });

  function createClient(opts?: Partial<{ baseUrl: string; apiKey: string; timeoutMs: number }>) {
    return new MtClient({
      baseUrl: opts?.baseUrl ?? 'http://localhost:5173',
      apiKey: opts?.apiKey ?? 'test-key',
      timeoutMs: opts?.timeoutMs ?? 5000,
    });
  }

  function mockResponse(status: number, body: unknown) {
    return {
      ok: status >= 200 && status < 300,
      status,
      text: () => Promise.resolve(JSON.stringify(body)),
      headers: new Headers(),
    } as Response;
  }

  // ── Bearer Token Injection ──────────────────────────────────────────────

  it('sends Authorization Bearer header on requests', async () => {
    mockFetch.mockResolvedValue(mockResponse(200, { id: 'MS-1', title: 'Test' }));

    const client = createClient({ apiKey: 'my-secret-key' });
    await client.get('/api/milestones/MS-1');

    expect(mockFetch).toHaveBeenCalledWith(
      'http://localhost:5173/api/milestones/MS-1',
      expect.objectContaining({
        headers: expect.objectContaining({
          Authorization: 'Bearer my-secret-key',
        }),
      }),
    );
  });

  it('sends Content-Type and Accept headers', async () => {
    mockFetch.mockResolvedValue(mockResponse(200, { ok: true }));

    const client = createClient();
    await client.post('/api/tasks', { title: 'test' });

    expect(mockFetch).toHaveBeenCalledWith(
      expect.any(String),
      expect.objectContaining({
        headers: expect.objectContaining({
          'Content-Type': 'application/json',
          Accept: 'application/json',
        }),
      }),
    );
  });

  // ── Success responses ──────────────────────────────────────────────────

  it('parses JSON response body on success', async () => {
    const data = { id: 'MS-1', title: 'Milestone One', status: 'active' };
    mockFetch.mockResolvedValue(mockResponse(200, data));

    const client = createClient();
    const result = await client.get('/api/milestones/MS-1');

    expect(result).toEqual(data);
  });

  it('serializes body as JSON for POST requests', async () => {
    mockFetch.mockResolvedValue(mockResponse(201, { id: 'TASK-1' }));

    const client = createClient();
    await client.post('/api/tasks', { title: 'New Task', assignee: 'agent-1' });

    expect(mockFetch).toHaveBeenCalledWith(
      expect.any(String),
      expect.objectContaining({
        body: JSON.stringify({ title: 'New Task', assignee: 'agent-1' }),
      }),
    );
  });

  // ── 401 Handling ───────────────────────────────────────────────────────

  it('throws MtCliError with Chinese message on 401', async () => {
    mockFetch.mockResolvedValue(
      mockResponse(401, { error: 'unauthorized', message: 'Invalid API key' }),
    );

    const client = createClient();
    await expect(client.get('/api/tasks')).rejects.toThrow(MtCliError);
    await expect(client.get('/api/tasks')).rejects.toMatchObject({
      status: 401,
      message: 'Invalid API key',
    });
  });

  it('includes suggestion in MtCliError on 401', async () => {
    mockFetch.mockResolvedValue(
      mockResponse(401, { error: 'unauthorized', message: 'Token expired' }),
    );

    const client = createClient();
    try {
      await client.get('/api/tasks');
      expect.unreachable('should have thrown');
    } catch (err) {
      expect(err).toBeInstanceOf(MtCliError);
      expect((err as MtCliError).suggestion).toContain('重新获取 API 密钥');
    }
  });

  // ── 409 Conflict ───────────────────────────────────────────────────────

  it('throws MtCliError with conflict message on 409', async () => {
    mockFetch.mockResolvedValue(
      mockResponse(409, { error: 'conflict', message: 'Task already claimed by another agent' }),
    );

    const client = createClient();
    try {
      await client.post('/api/tasks/TASK-1/claim', { assignee: 'agent-1' });
      expect.unreachable('should have thrown');
    } catch (err) {
      expect(err).toBeInstanceOf(MtCliError);
      expect((err as MtCliError).status).toBe(409);
      expect((err as MtCliError).message).toContain('Task already claimed');
    }
  });

  // ── Timeout Handling ───────────────────────────────────────────────────

  it('throws MtCliError on timeout', async () => {
    const abortError = new DOMException('The operation was aborted', 'AbortError');
    mockFetch.mockRejectedValue(abortError);

    const client = createClient({ timeoutMs: 100 });
    try {
      await client.get('/api/milestones/MS-1');
      expect.unreachable('should have thrown');
    } catch (err) {
      expect(err).toBeInstanceOf(MtCliError);
      expect((err as MtCliError).status).toBe(0);
      expect((err as MtCliError).message).toContain('请求超时');
    }
  });

  // ── Connection Error ───────────────────────────────────────────────────

  it('throws MtCliError on network failure', async () => {
    mockFetch.mockRejectedValue(new TypeError('fetch failed'));

    const client = createClient();
    try {
      await client.get('/api/milestones/MS-1');
      expect.unreachable('should have thrown');
    } catch (err) {
      expect(err).toBeInstanceOf(MtCliError);
      expect((err as MtCliError).status).toBe(0);
      expect((err as MtCliError).message).toContain('无法连接到服务器');
    }
  });

  // ── Malformed Response ─────────────────────────────────────────────────

  it('throws error on non-JSON response', async () => {
    mockFetch.mockResolvedValue({
      ok: true,
      status: 200,
      text: () => Promise.resolve('<html>Not JSON</html>'),
    } as Response);

    const client = createClient();
    await expect(client.get('/api/milestones/MS-1')).rejects.toThrow('无法解析服务器响应');
  });

  it('throws MtCliError on non-JSON error response', async () => {
    mockFetch.mockResolvedValue({
      ok: false,
      status: 500,
      text: () => Promise.resolve('Internal Server Error'),
    } as Response);

    const client = createClient();
    try {
      await client.get('/api/milestones/MS-1');
      expect.unreachable('should have thrown');
    } catch (err) {
      expect(err).toBeInstanceOf(MtCliError);
      expect((err as MtCliError).status).toBe(500);
      expect((err as MtCliError).message).toContain('非 JSON 响应');
    }
  });

  // ── Logging ────────────────────────────────────────────────────────────

  it('logs request URL and status on failure', async () => {
    const consoleSpy = vi.spyOn(console, 'error').mockImplementation(() => {});
    mockFetch.mockResolvedValue(
      mockResponse(404, { error: 'not_found', message: 'Milestone MS-99 not found' }),
    );

    const client = createClient();
    try {
      await client.get('/api/milestones/MS-99');
    } catch {
      // expected
    }

    expect(consoleSpy).toHaveBeenCalledWith(
      expect.stringContaining('GET http://localhost:5173/api/milestones/MS-99 → 404'),
    );
    consoleSpy.mockRestore();
  });

  // ── Base URL normalization ─────────────────────────────────────────────

  it('strips trailing slashes from base URL', async () => {
    mockFetch.mockResolvedValue(mockResponse(200, { ok: true }));

    const client = createClient({ baseUrl: 'http://localhost:5173/' });
    await client.get('/api/tasks');

    expect(mockFetch).toHaveBeenCalledWith(
      'http://localhost:5173/api/tasks',
      expect.anything(),
    );
  });

  // ── PATCH method ───────────────────────────────────────────────────────

  it('sends PATCH requests with body', async () => {
    mockFetch.mockResolvedValue(mockResponse(200, { id: 'TASK-1', status: 'in-progress' }));

    const client = createClient();
    await client.patch('/api/tasks/TASK-1/progress', { progressMessage: 'Working on it' });

    expect(mockFetch).toHaveBeenCalledWith(
      expect.any(String),
      expect.objectContaining({
        body: JSON.stringify({ progressMessage: 'Working on it' }),
      }),
    );
  });
});

