    const body = JSON.parse(call[1].body);
    expect(body).toEqual({ assignee: 'agent-beta' });
  });

  it('handles 409 conflict on claim', async () => {
    const mockFetch = vi.fn().mockResolvedValue({
      ok: false,
      status: 409,
      text: () =>
        Promise.resolve(
          JSON.stringify({
            error: 'conflict',
            message: 'Task already claimed by agent-alpha',
