    });
    const result2 = await client.post<TaskResponse>('/api/tasks/TASK-10/claim', {
      assignee: 'agent-alpha',
    });

    expect(result1.assignee).toBe('agent-alpha');
    expect(result2.assignee).toBe('agent-alpha');
  });
});

